create table if not exists public.source_records (id uuid primary key default gen_random_uuid(), source_url text not null, source_type text not null default 'web', title text, canonical_url text, first_seen_at timestamptz not null default now(), last_checked_at timestamptz, status text not null default 'active', metadata jsonb not null default '{}'::jsonb);
create table if not exists public.source_snapshots (id uuid primary key default gen_random_uuid(), source_record_id uuid references public.source_records(id) on delete cascade, fetched_at timestamptz not null default now(), raw_content text, normalized_content text, content_hash text not null, metadata jsonb not null default '{}'::jsonb);
create table if not exists public.source_usage_log (id uuid primary key default gen_random_uuid(), source_snapshot_id uuid references public.source_snapshots(id) on delete set null, protocol_id uuid, phase text not null, usage_reason text, created_at timestamptz not null default now());
